```class Solution {
public:
    int minMovesToMakePalindrome(string s) {
        int n = s.size();
        int res = 0;
        string t = s;
        reverse(t.begin(), t.end());
        for (int i = 0; i < n; i++) {
            if (s[i] != t[i]) {
                res++;
                for (int j = i; j >= 0 && s[j] != t[i]; j--) {
                    swap(s[j], s[j + 1]);
                    res++;
                }
            }
        }
        return res;
    }
};```
